import{_ as o,o as l,c as d,ai as a}from"./chunks/framework.CsYGeNYI.js";const f=JSON.parse('{"title":"提升模式","description":"","frontmatter":{"read_when":["调整提升模式默认值、允许列表或斜杠命令行为"],"summary":"提升的 exec 模式和 /elevated 指令","title":"提升模式","x-i18n":{"generated_at":"2026-02-03T07:55:23Z","model":"claude-opus-4-5","provider":"pi","source_hash":"83767a01609304026d145feb0aa0b0533e8cf8b16cd200f724d9e3e8cf2920c3","source_path":"tools/elevated.md","workflow":15}},"headers":[],"relativePath":"zh-CN/tools/elevated.md","filePath":"zh-CN/tools/elevated.md","lastUpdated":1771906665000}'),t={name:"zh-CN/tools/elevated.md"};function c(s,e,i,r,n,h){return l(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="提升模式-elevated-指令" tabindex="-1"><a class="header-anchor" href="#提升模式-elevated-指令">#</a> 提升模式（/elevated 指令）</h1><h2 id="功能说明" tabindex="-1"><a class="header-anchor" href="#功能说明">#</a> 功能说明</h2><ul><li><code>/elevated on</code> 在 Gateway 网关主机上运行并保留 exec 审批（与 <code>/elevated ask</code> 相同）。</li><li><code>/elevated full</code> 在 Gateway 网关主机上运行<strong>并</strong>自动批准 exec（跳过 exec 审批）。</li><li><code>/elevated ask</code> 在 Gateway 网关主机上运行但保留 exec 审批（与 <code>/elevated on</code> 相同）。</li><li><code>on</code>/<code>ask</code> <strong>不会</strong>强制 <code>exec.security=full</code>；配置的安全/询问策略仍然适用。</li><li>仅在智能体被<strong>沙箱隔离</strong>时改变行为（否则 exec 已经在主机上运行）。</li><li>指令形式：<code>/elevated on|off|ask|full</code>、<code>/elev on|off|ask|full</code>。</li><li>仅接受 <code>on|off|ask|full</code>；其他任何内容返回提示且不改变状态。</li></ul><h2 id="它控制什么-以及不控制什么" tabindex="-1"><a class="header-anchor" href="#它控制什么-以及不控制什么">#</a> 它控制什么（以及不控制什么）</h2><ul><li><strong>可用性门控</strong>：<code>tools.elevated</code> 是全局基线。<code>agents.list[].tools.elevated</code> 可以进一步限制每个智能体的提升（两者都必须允许）。</li><li><strong>每会话状态</strong>：<code>/elevated on|off|ask|full</code> 为当前会话键设置提升级别。</li><li><strong>内联指令</strong>：消息内的 <code>/elevated on|ask|full</code> 仅适用于该消息。</li><li><strong>群组</strong>：在群聊中，仅当智能体被提及时才遵守提升指令。绕过提及要求的纯命令消息被视为已提及。</li><li><strong>主机执行</strong>：elevated 强制 <code>exec</code> 到 Gateway 网关主机；<code>full</code> 还设置 <code>security=full</code>。</li><li><strong>审批</strong>：<code>full</code> 跳过 exec 审批；<code>on</code>/<code>ask</code> 在允许列表/询问规则要求时遵守审批。</li><li><strong>非沙箱隔离智能体</strong>：对位置无影响；仅影响门控、日志和状态。</li><li><strong>工具策略仍然适用</strong>：如果 <code>exec</code> 被工具策略拒绝，则无法使用 elevated。</li><li><strong>与 <code>/exec</code> 分开</strong>：<code>/exec</code> 为授权发送者调整每会话默认值，不需要 elevated。</li></ul><h2 id="解析顺序" tabindex="-1"><a class="header-anchor" href="#解析顺序">#</a> 解析顺序</h2><ol><li>消息上的内联指令（仅适用于该消息）。</li><li>会话覆盖（通过发送仅含指令的消息设置）。</li><li>全局默认值（配置中的 <code>agents.defaults.elevatedDefault</code>）。</li></ol><h2 id="设置会话默认值" tabindex="-1"><a class="header-anchor" href="#设置会话默认值">#</a> 设置会话默认值</h2><ul><li>发送一条<strong>仅</strong>包含指令的消息（允许空白），例如 <code>/elevated full</code>。</li><li>发送确认回复（<code>Elevated mode set to full...</code> / <code>Elevated mode disabled.</code>）。</li><li>如果 elevated 访问被禁用或发送者不在批准的允许列表中，指令会回复一个可操作的错误且不改变会话状态。</li><li>发送不带参数的 <code>/elevated</code>（或 <code>/elevated:</code>）以查看当前的 elevated 级别。</li></ul><h2 id="可用性-允许列表" tabindex="-1"><a class="header-anchor" href="#可用性-允许列表">#</a> 可用性 + 允许列表</h2><ul><li>功能门控：<code>tools.elevated.enabled</code>（即使代码支持，也可以通过配置将默认值设为关闭）。</li><li>发送者允许列表：<code>tools.elevated.allowFrom</code>，带有每提供商允许列表（例如 <code>discord</code>、<code>whatsapp</code>）。</li><li>每智能体门控：<code>agents.list[].tools.elevated.enabled</code>（可选；只能进一步限制）。</li><li>每智能体允许列表：<code>agents.list[].tools.elevated.allowFrom</code>（可选；设置时，发送者必须同时匹配全局 + 每智能体允许列表）。</li><li>Discord 回退：如果省略 <code>tools.elevated.allowFrom.discord</code>，则使用 <code>channels.discord.dm.allowFrom</code> 列表作为回退。设置 <code>tools.elevated.allowFrom.discord</code>（即使是 <code>[]</code>）以覆盖。每智能体允许列表<strong>不</strong>使用回退。</li><li>所有门控都必须通过；否则 elevated 被视为不可用。</li></ul><h2 id="日志-状态" tabindex="-1"><a class="header-anchor" href="#日志-状态">#</a> 日志 + 状态</h2><ul><li>Elevated exec 调用以 info 级别记录。</li><li>会话状态包括 elevated 模式（例如 <code>elevated=ask</code>、<code>elevated=full</code>）。</li></ul>',13)])])}const u=o(t,[["render",c]]);export{f as __pageData,u as default};
